    private MessageDefaults() {
    }

    public static Map<String, Object> defaults(LanguageRegistry registry) {
        return new LinkedHashMap<String, Object>(registry == LanguageRegistry.DE ? DE : EN);
    }

    public static Map<String, List<String>> sectionComments(LanguageRegistry registry) {
        LinkedHashMap<String, List<String>> copy = new LinkedHashMap<String, List<String>>();
        for (Map.Entry<String, List<String>> e : (registry == LanguageRegistry.DE ? SEC_DE : SEC_EN).entrySet()) {
            copy.put(e.getKey(), new ArrayList<String>(e.getValue()));
        }
        return copy;
    }

    public static int requiredKeys() {
        return EN.size();
    }

    private static void def(String k, Object en, Object de) {
        EN.put(k, en);
        DE.put(k, de);
    }

    private static void sec(String k, List<String> en, List<String> de) {
        SEC_EN.put(k, en);
        SEC_DE.put(k, de);
    }

    private static List<Object> list(Object... xs) {
        return new ArrayList<Object>(Arrays.asList(xs));
    }

    private static List<String> slist(String... xs) {
        return new ArrayList<String>(Arrays.asList(xs));
    }

    private static Map<String, Object> map(Object... kv) {
        LinkedHashMap<String, Object> m = new LinkedHashMap<String, Object>();
        for (int i = 0; i < kv.length; i += 2) {
            m.put((String) kv[i], kv[i + 1]);
        }
        return m;
    }
